<template>
  <div class="post-detail">
    <v-btn
      class="fab-back"
      color="#111"
      fab
      large
      @click="goBack"
      title="Back to Posts"
      elevation="8"
    >
      <v-icon color="white">mdi-arrow-left</v-icon>
    </v-btn>
    <div v-if="post">
      <h1 class="post-title">{{ post.Title }}</h1>
      <div class="post-date">{{ formatDate(post.Date) }}</div>
      <div class="post-body" v-html="post.Body"></div>
    </div>
    <div v-else>
      <p>Post not found.</p>
    </div>
  </div>
</template>

<script>
export default {
  name: 'PostDetail',
  data() {
    return {
      post: null,
    };
  },
  created() {
    const id = this.$route.params.id;
    const page = this.$route.query.page || 1;
    // Try to get posts from localStorage (cache)
    const cache = localStorage.getItem('posts_cache');
    let posts = [];
    if (cache) {
      try {
        posts = JSON.parse(cache).filter(p => p.Published === 'Yes');
      } catch (e) {
        // eslint-disable-next-line no-empty
        // Intentionally ignore JSON parse errors
      }
    }
    if (posts.length && posts[id]) {
      this.post = posts[id];
    } else {
      // fallback: fetch posts from API
      fetch('https://script.googleusercontent.com/macros/echo?user_content_key=AY5xjrSqgdJAjxFysEVjo1e9EOIjYyPpc54Ii4sM1Mq5eTY5ul37WLo4X9oSoW7PZ85rV1HWO4VPrwEFvqn3gKIGhImjH27pooRjbWhsRqmcBtyON6L38wBKx2oOKtb6tYreoCZsm5w4QTv9h_Iup-ni6IU_dhltZr0AuZFu8iV3Mmo0AXnuVtiZOAXlbhyDYSCvND0ghhdrR2L56oe3UuJ3iKjiLE0S5TkPo_ci_NfrveVF1OADiilNdyGpLD34cZUb6EL_cNiUGJcQdxu3Y2BrguiIW3DwXKzt0asBOkzK&lib=MjeheYeZQDu8ojW5QI4yDNFymUS9JgsUa')
        .then(res => res.json())
        .then(data => {
          const filtered = Array.isArray(data) ? data.filter(p => p.Published === 'Yes') : [];
          this.post = filtered[id] || null;
        });
    }
    this.page = page;
  },
  methods: {
    goBack() {
      this.$router.push({ name: 'PostsPage', query: { page: this.page } });
    },
    formatDate(dateStr) {
      if (!dateStr) return '';
      const date = new Date(dateStr);
      return date.toLocaleDateString(undefined, { year: 'numeric', month: 'long', day: 'numeric' });
    }
  }
};
</script>

