
<template>
  <div class="posts-content">
    <h1>Posts</h1>
    <div v-if="loading" class="loading">Loading posts...</div>
    <div v-else>
      <div v-if="posts.length === 0">No posts found.</div>
      <div v-for="(post, idx) in pagedPosts" :key="idx" class="post-block">
        <h2 class="post-title">
          <router-link :to="{ name: 'PostDetail', params: { id: (pageStart + idx) }, query: { page: currentPage } }">
            {{ post.Title }}
          </router-link>
        </h2>
        <div class="post-date">{{ formatDate(post.Date) }}</div>
        <div class="post-body" v-html="post.Body"></div>
      </div>
      <div v-if="totalPages > 1" class="pagination">
        <button @click="prevPage" :disabled="currentPage === 1">Prev</button>
        <span>Page {{ currentPage }} of {{ totalPages }}</span>
        <button @click="nextPage" :disabled="currentPage === totalPages">Next</button>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'PostsPage',
  data() {
    return {
      posts: [],
      loading: true,
      currentPage: 1,
      pageSize: 3
    };
  },
  computed: {
    totalPages() {
      return Math.ceil(this.posts.length / this.pageSize);
    },
    pagedPosts() {
      const start = (this.currentPage - 1) * this.pageSize;
      return this.posts.slice(start, start + this.pageSize);
    },
    pageStart() {
      return (this.currentPage - 1) * this.pageSize;
    }
  },
  methods: {
    nextPage() {
      if (this.currentPage < this.totalPages) this.currentPage++;
    },
    prevPage() {
      if (this.currentPage > 1) this.currentPage--;
    },
    async fetchPosts() {
      const cacheKey = 'posts_cache';
      const cacheTimeKey = 'posts_cache_time';
      const now = Date.now();
      const cacheTime = parseInt(localStorage.getItem(cacheTimeKey), 10);
      const cache = localStorage.getItem(cacheKey);
      if (cache && cacheTime && now - cacheTime < 60000) {
        try {
          const cachedPosts = JSON.parse(cache);
          this.posts = Array.isArray(cachedPosts) ? cachedPosts.filter(post => post.Published === 'Yes') : [];
          this.loading = false;
          // Don't override currentPage if set from query
          if (!this.pageFromQuery) this.currentPage = 1;
          return;
        } catch (e) {
          // eslint-disable-next-line no-empty
          // Intentionally ignore JSON parse errors
        }
      }
      try {
        const response = await fetch('https://script.googleusercontent.com/macros/echo?user_content_key=AY5xjrSqgdJAjxFysEVjo1e9EOIjYyPpc54Ii4sM1Mq5eTY5ul37WLo4X9oSoW7PZ85rV1HWO4VPrwEFvqn3gKIGhImjH27pooRjbWhsRqmcBtyON6L38wBKx2oOKtb6tYreoCZsm5w4QTv9h_Iup-ni6IU_dhltZr0AuZFu8iV3Mmo0AXnuVtiZOAXlbhyDYSCvND0ghhdrR2L56oe3UuJ3iKjiLE0S5TkPo_ci_NfrveVF1OADiilNdyGpLD34cZUb6EL_cNiUGJcQdxu3Y2BrguiIW3DwXKzt0asBOkzK&lib=MjeheYeZQDu8ojW5QI4yDNFymUS9JgsUa');
        const data = await response.json();
        this.posts = Array.isArray(data) ? data.filter(post => post.Published === 'Yes') : [];
        localStorage.setItem(cacheKey, JSON.stringify(this.posts));
        localStorage.setItem(cacheTimeKey, now.toString());
        if (!this.pageFromQuery) this.currentPage = 1;
      } catch (e) {
        this.posts = [];
      } finally {
        this.loading = false;
      }
    },
    formatDate(dateStr) {
      if (!dateStr) return '';
      const date = new Date(dateStr);
      return date.toLocaleDateString(undefined, { year: 'numeric', month: 'long', day: 'numeric' });
    },
  },
  watch: {
    '$route.query.page': {
      immediate: true,
      handler(newPage) {
        if (newPage) {
          this.pageFromQuery = true;
          this.currentPage = parseInt(newPage, 10) || 1;
        } else {
          this.pageFromQuery = false;
          this.currentPage = 1;
        }
      }
    }
  },
  mounted() {
    this.fetchPosts();
  }
};
</script>

